#include <stdio.h>
#include <stdlib.h>

// Structure for a trie node
typedef struct Node {
    struct Node* links[2];
} Node;

// Function to create a new trie node
Node* createNode() {
    Node* node = (Node*) malloc(sizeof(Node));
    node->links[0] = NULL;
    node->links[1] = NULL;
    return node;
}

// Function to insert a number into the trie
void insert(Node* root, int num) {
    Node* node = root;
    for (int i = 31; i >= 0; i--) {
        int bit = (num >> i) & 1;
        if (node->links[bit] == NULL) {
            node->links[bit] = createNode();
        }
        node = node->links[bit];
    }
}

// Function to find maximum XOR for a given number
int findMax(Node* root, int num) {
    Node* node = root;
    int maxNum = 0;
    for (int i = 31; i >= 0; i--) {
        int bit = (num >> i) & 1;
        if (node->links[1 - bit] != NULL) {
            maxNum = maxNum | (1 << i);
            node = node->links[1 - bit];
        } else {
            node = node->links[bit];
        }
    }
    return maxNum;
}

// Function to perform offline max XOR queries
int* maxXorQueries(int* arr, int arrSize, int** queries, int queriesSize, int* queriesColSize, int* returnSize) {
    // Sort array
    for (int i = 0; i < arrSize - 1; i++) {
        for (int j = i + 1; j < arrSize; j++) {
            if (arr[i] > arr[j]) {
                int temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
            }
        }
    }

    // Store queries with index
    int** offlineQueries = (int**) malloc(queriesSize * sizeof(int*));
    for (int i = 0; i < queriesSize; i++) {
        offlineQueries[i] = (int*) malloc(3 * sizeof(int));
        offlineQueries[i][0] = queries[i][1];
        offlineQueries[i][1] = queries[i][0];
        offlineQueries[i][2] = i;
    }

    // Sort queries based on m
    for (int i = 0; i < queriesSize - 1; i++) {
        for (int j = i + 1; j < queriesSize; j++) {
            if (offlineQueries[i][0] > offlineQueries[j][0]) {
                int* temp = offlineQueries[i];
                offlineQueries[i] = offlineQueries[j];
                offlineQueries[j] = temp;
            }
        }
    }

    // Result array
    int* ans = (int*) malloc(queriesSize * sizeof(int));

    // Trie object
    Node* trie = createNode();

    // Array pointer
    int i = 0;

    // Process queries
    for (int k = 0; k < queriesSize; k++) {
