// Function to perform offline max XOR queries
public List<Integer> maxXorQueries(List<Integer> arr, List<List<Integer>> queries) {
    // Sort array
    Collections.sort(arr);

    // Store queries with index
    List<int[]> offlineQueries = new ArrayList<>();
    for (int i = 0; i < queries.size(); i++) {
        offlineQueries.add(new int[]{queries.get(i).get(1), queries.get(i).get(0), i});
    }

    // Sort queries based on m
    offlineQueries.sort(Comparator.comparingInt(a -> a[0]));

    // Result array
    List<Integer> ans = new ArrayList<>(Collections.nCopies(queries.size(), 0));

    // Trie object
    Node trie = new Node();

    // Array pointer
    int i = 0;

    // Process queries
    for (int[] query : offlineQueries) {
        while (i < arr.size() && arr.get(i) <= query[0]) {
            insert(trie, arr.get(i));
            i++;
        }
        if (i != 0) {
            ans.set(query[2], findMax(trie, query[1]));
        } else {
            ans.set(query[2], -1);
        }
    }
    return ans;
}

